"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { RelationshipScatter } from "@/components/charts/RelationshipScatter";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  AFFINITY_PRODUCTS,
  AFFINITY_AVG_REPEAT,
  LOYALTY_PAIRS,
  CATEGORY_BREADTH,
  TXN_ONLY_PRODUCTS,
  TXN_ONLY_TOTAL,
  VERDICT_COLOR_AFFINITY,
  VERDICT_LABEL_AFFINITY,
  affinityMetrics,
  affinityAI,
  type AffinityProduct,
  type AffinityVerdict,
} from "@/features/customers/api/customers-product-affinity-data";
import "./affinity.css";

const PERIOD_LABELS = ["Last 90 days", "Last 12 months", "All time"];

const SECTIONS = [
  { id: "s-map", label: "Relationship map" },
  { id: "s-gateways", label: "Gateways" },
  { id: "s-pairs", label: "Loyalty pairs" },
  { id: "s-breadth", label: "Category breadth" },
  { id: "s-txn", label: "Transaction-only" },
];

export default function ProductAffinityPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const [activeSection, setActiveSection] = useState("s-map");
  const [selIdx, setSelIdx] = useState(0);
  const { openBridge } = useBridge();

  const scrollTo = (id: string) => {
    setActiveSection(id);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  const selProduct = AFFINITY_PRODUCTS[selIdx];

  return (
    <div className="customers-affinity-page">
      <DeptHeader
        dept="customers"
        title="Product Affinity"
        meta={
          <>
            <span className="live">Live</span> · 214 products · ranked by repeat-customer creation, not units sold
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("customers")}
            >
              Promote gateways → Bridge
            </button>
          </>
        }
      />
      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Products tracked</div>
          <div className="metric-v">{affinityMetrics.tracked}</div>
          <div className="metric-yoy flat">— vs LY</div>
        </div>
        <div className="metric">
          <div className="metric-l">Gateway products</div>
          <div className="metric-v green">{affinityMetrics.gateways}</div>
          <div className="metric-yoy up">↑ 2 <span className="yl">vs LY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">Avg repeat-creation</div>
          <div className="metric-v">{affinityMetrics.avgRepeat}%</div>
          <div className="metric-yoy down">↓ 3pp <span className="yl">YoY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">Multi-category LTV lift</div>
          <div className="metric-v purple">{affinityMetrics.multiCatLift}</div>
          <div className="metric-yoy up">↑ from {affinityMetrics.multiCatLY} <span className="yl">LY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">Transaction-only revenue</div>
          <div className="metric-v red">{affinityMetrics.txnOnlyRev}</div>
          <div className="metric-yoy down">{affinityMetrics.txnOnlyDelta} <span className="yl">YoY</span></div>
        </div>
      </div>

      <AIStrip label={affinityAI.label} meta={affinityAI.meta} cards={affinityAI.cards} />

      <div className="secnav">
        {SECTIONS.map((s) => (
          <button
            key={s.id}
            type="button"
            className={activeSection === s.id ? "active" : ""}
            onClick={() => scrollTo(s.id)}
          >
            {s.label}
          </button>
        ))}
      </div>

      {/* 1 — Relationship map */}
      <section className="section" id="s-map">
        <SectionLabel>
          <span className="n">1</span> Relationship map <span className="sl-note">— which products make customers, and which just make sales?</span>
        </SectionLabel>
        <div className="icard">
          <div className="ic-head">
            <div>
              <div className="ic-title">Units sold versus repeat-customer creation</div>
              <div className="ic-sub">
                Each bubble is a product · size = customer lifetime value · top-left beats top-right
              </div>
            </div>
            <div className="legend">
              <span><i style={{ background: "#8b6fc7" }} />Protect</span>
              <span><i style={{ background: "#1D9E75" }} />Grow</span>
              <span><i style={{ background: "#5B7CB0" }} />Watch</span>
              <span><i style={{ background: "#d64545" }} />Release</span>
            </div>
          </div>
          <RelationshipScatter data={AFFINITY_PRODUCTS} selIdx={selIdx} onSelect={setSelIdx} />
          <ProductDetail product={selProduct} />
          <div className="dc-read">
            The vertical axis is the one that matters: how often a product&rsquo;s buyers come back. A bubble can sit far to the right — a big seller — and still hug the floor, meaning it generates orders but almost no customers. Your <b>Monthly Subscription</b> sits highest of all yet barely registers on volume; your <b>Graduation Bouquet</b> is the opposite. Volume and relationship value are different things, and this room ranks on the second.
          </div>
        </div>
      </section>

      {/* 2 — Gateways */}
      <section className="section" id="s-gateways">
        <SectionLabel>
          <span className="n">2</span> Gateway products <span className="sl-note">— the first orders most likely to turn into a second one</span>
        </SectionLabel>
        <div className="row-card">
          <GatewayList />
        </div>
        <div className="dc-read ok">
          These are the products worth putting in front of <b>new</b> customers — a first order here is far more likely to start a relationship. Acquisition that lands on a gateway compounds; acquisition that lands on a one-time product doesn&rsquo;t. This is the list to feed back into Growth&rsquo;s first-purchase targeting.
        </div>
      </section>

      {/* 3 — Loyalty pairs */}
      <section className="section" id="s-pairs">
        <SectionLabel>
          <span className="n">3</span> Loyalty pairs <span className="sl-note">— combinations that build more valuable customers, ranked by LTV lift (not basket size)</span>
        </SectionLabel>
        <div className="row-card">
          <PairList />
        </div>
        <div className="dc-read">
          These aren&rsquo;t &ldquo;frequently bought together&rdquo; — that&rsquo;s a merchandising number. This is ranked by how much more a customer is worth when they buy <b>both</b>. The strongest pair, Flowers + Chocolate, lifts lifetime value to <b>2.1×</b> — and only 14% of customers attach it. The highest-value pairings are the least attached, which is exactly where the upside lives.
        </div>
      </section>

      {/* 4 — Category breadth */}
      <section className="section" id="s-breadth">
        <SectionLabel>
          <span className="n">4</span> Category breadth <span className="sl-note">— do customers stay in one aisle, or broaden — and does it matter?</span>
        </SectionLabel>
        <div className="row-card">
          <BreadthList />
        </div>
        <div className="dc-read warn">
          Breadth is loyalty: customers who buy across three or more categories repeat at <b>63%</b> versus <b>24%</b> for single-category buyers — more than double. Yet <b>58%</b> of your base has only ever bought from one category. Moving a single-category buyer to a second category is one of the highest-leverage moves available, and most of your customers haven&rsquo;t made it.
        </div>
      </section>

      {/* 5 — Transaction-only */}
      <section className="section" id="s-txn">
        <SectionLabel>
          <span className="n">5</span> Transaction-only products <span className="sl-note">— real revenue, no relationship — know what these are, don&rsquo;t build growth on them</span>
        </SectionLabel>
        <div className="gc-intro">
          Ranked by <b>revenue that produces no repeat customer</b> · {TXN_ONLY_TOTAL} total · these sell fine — they just don&rsquo;t compound
        </div>
        <div className="row-card">
          <TxnList />
        </div>
        <div className="dc-read">
          This revenue is real and worth keeping — but it&rsquo;s transactional by nature (occasions, gifts that don&rsquo;t recur). The mistake is counting it as a growth engine. Hold these for the cash they bring, set expectations honestly, and put your relationship effort behind the gateways instead.
        </div>
      </section>

      <div className="foot-note">
        <span className="mk" />
        <p>
          Most product reports rank by what sells. This one ranks by what <b>lasts</b> — because a catalogue has two jobs that look identical on a revenue chart and behave nothing alike: some products bring in money once, and some bring in customers who keep coming back. Knowing which is which is the difference between a busy quarter and a growing business.
        </p>
      </div>
    </div>
  );
}

/* ───────── Product detail card ───────── */
function ProductDetail({ product }: { product: AffinityProduct }) {
  const { openBridge } = useBridge();
  const col = VERDICT_COLOR_AFFINITY[product.verdict];
  const numCls =
    product.verdict === "protect"
      ? "purple"
      : product.verdict === "grow"
      ? "green"
      : product.verdict === "release"
      ? "red"
      : "";

  const reads: Record<AffinityVerdict, string> = {
    protect: `${product.name} turns a first-time buyer into a repeat customer ${product.rep}% of the time — the highest in your catalogue. Protect it: feature it, never discount it, and steer new customers toward it.`,
    grow: `A first order of ${product.name} comes back ${product.rep}% of the time, well above the ${AFFINITY_AVG_REPEAT}% catalogue average. This is a relationship-starter — worth putting in front of new customers.`,
    watch: `${product.name} sells, but only ${product.rep}% of its buyers return. Treat it as a transaction product: keep it for the revenue it brings, don't expect it to build your base.`,
    release: `${product.name} moves little volume and almost never repeats (${product.rep}%). A candidate to retire or rework unless it serves a deliberate niche.`,
  };

  return (
    <div className="pd-card" style={{ ["--pdc" as string]: col } as React.CSSProperties}>
      <div className="pd-grid">
        <div>
          <div className="pd-top">
            <span className="pd-name">{product.name}</span>
            <span className={`vpill ${product.verdict}`}>{VERDICT_LABEL_AFFINITY[product.verdict]}</span>
          </div>
          <div className="pd-stats">
            <div className="pd-stat">
              <div className="pdl">Repeat-creation</div>
              <div className={`pdv ${numCls}`}>{product.rep}%</div>
            </div>
            <div className="pd-stat">
              <div className="pdl">Lifetime value</div>
              <div className="pdv">{product.ltv}</div>
            </div>
            <div className="pd-stat">
              <div className="pdl">Units sold</div>
              <div className="pdv">{product.vol.toLocaleString()}</div>
            </div>
          </div>
          <div className="pd-read">{reads[product.verdict]}</div>
        </div>
        <div className="pd-right">
          <div className="pd-rt">What these customers buy next</div>
          {product.next.map(([name, pct]) => (
            <div key={name} className="pd-nrow">
              <span className="pd-nname">{name}</span>
              <span className="pd-npct">{pct}%</span>
            </div>
          ))}
          <button className="pd-bridge" type="button" onClick={() => openBridge("customers")}>
            Send to Bridge →
          </button>
        </div>
      </div>
    </div>
  );
}

/* ───────── Gateway list ───────── */
function GatewayList() {
  const rows = useMemo(
    () => [...AFFINITY_PRODUCTS].sort((a, b) => b.rep - a.rep).slice(0, 6),
    [],
  );
  const mx = rows[0].rep;
  return (
    <>
      {rows.map((p, i) => {
        const col = VERDICT_COLOR_AFFINITY[p.verdict];
        const numCls =
          p.verdict === "protect" ? "purple" : p.verdict === "grow" ? "green" : "";
        return (
          <div
            key={p.name}
            className="orow"
            style={{ ["--st" as string]: col } as React.CSSProperties}
          >
            <span className="o-rank">{i + 1}</span>
            <div>
              <div className="o-name">{p.name}</div>
              <div className="o-sub">{p.vol.toLocaleString()} sold · {p.ltv} LTV</div>
            </div>
            <div className="o-bar">
              <i
                style={{
                  ["--w" as string]: `${Math.round((p.rep / mx) * 100)}%`,
                  background: `linear-gradient(180deg,${col},${col})`,
                } as React.CSSProperties}
              />
            </div>
            <div>
              <div className={`o-num ${numCls}`}>{p.rep}%</div>
              <div className="o-numu">come back</div>
            </div>
            <span className={`vpill ${p.verdict}`}>{VERDICT_LABEL_AFFINITY[p.verdict]}</span>
          </div>
        );
      })}
    </>
  );
}

/* ───────── Pair list ───────── */
function PairList() {
  const mx = Math.max(...LOYALTY_PAIRS.map((p) => p.lift));
  return (
    <>
      {LOYALTY_PAIRS.map((p, i) => (
        <div key={p.pair} className="prow">
          <span className="o-rank">{i + 1}</span>
          <div>
            <div className="p-pair">{p.pair}</div>
            <div className="p-sub">{p.coBuy}% of customers buy both</div>
          </div>
          <div className="o-bar">
            <i
              style={{
                ["--w" as string]: `${Math.round((p.lift / mx) * 100)}%`,
                background: "linear-gradient(180deg,#33b088,#1D9E75)",
              } as React.CSSProperties}
            />
          </div>
          <div>
            <div className="p-lift">{p.lift.toFixed(1)}×</div>
            <div className="p-liftu">LTV lift</div>
          </div>
        </div>
      ))}
    </>
  );
}

/* ───────── Category breadth list ───────── */
function BreadthList() {
  const mx = Math.max(...CATEGORY_BREADTH.map((b) => b.repeatPct));
  return (
    <>
      {CATEGORY_BREADTH.map((b) => (
        <div key={b.label} className="brd">
          <div className="brd-c">{b.label}</div>
          <div className="brd-bar">
            <i
              style={{ ["--w" as string]: `${Math.round((b.repeatPct / mx) * 100)}%` } as React.CSSProperties}
            />
          </div>
          <div className="brd-rep green">{b.repeatPct}%</div>
          <div className="brd-share">
            <b>{b.sharePct}%</b> of base
          </div>
        </div>
      ))}
    </>
  );
}

/* ───────── Transaction-only list ───────── */
function TxnList() {
  const mx = Math.max(...TXN_ONLY_PRODUCTS.map((t) => t.revenue));
  return (
    <>
      {TXN_ONLY_PRODUCTS.map((t, i) => (
        <div
          key={t.name}
          className="orow"
          style={{ ["--st" as string]: "var(--amber)" } as React.CSSProperties}
        >
          <span className="o-rank">{i + 1}</span>
          <div>
            <div className="o-name">{t.name}</div>
            <div className="o-sub">{t.sub}</div>
          </div>
          <div className="o-bar">
            <i
              style={{
                ["--w" as string]: `${Math.round((t.revenue / mx) * 100)}%`,
                background: "linear-gradient(180deg,#d4a13f,#b88a2a)",
              } as React.CSSProperties}
            />
          </div>
          <div>
            <div className="o-num amber">${(t.revenue / 1000).toFixed(0)}K</div>
            <div className="o-numu">no-repeat rev</div>
          </div>
          <span className={`vpill ${t.verdict}`}>{VERDICT_LABEL_AFFINITY[t.verdict]}</span>
        </div>
      ))}
    </>
  );
}
