/**
 * Mock data for Customers · Product Affinity.
 *
 * Five instruments:
 *  1. Relationship map — units sold × repeat-customer rate, bubble = LTV
 *  2. Gateway products — top by repeat-creation
 *  3. Loyalty pairs — ranked by LTV lift, not basket-attach
 *  4. Category breadth — repeat rate by number of categories purchased
 *  5. Transaction-only products — revenue that builds no relationship
 *
 * USD currency per canonical rule.
 */

export type AffinityVerdict = "protect" | "grow" | "watch" | "release";

