export interface AffinityProduct {
  name: string;
  /** Units sold in the period. */
  vol: number;
  /** % of first-time buyers who come back. */
  rep: number;
  /** Display LTV like "$8,900". */
  ltv: string;
  /** Numeric LTV in USD — drives bubble radius. */
  ltvN: number;
  verdict: AffinityVerdict;
  /** Optional emphasis label in the scatter (for the named bubbles). */
  emphasize?: boolean;
  /** Top-3 next purchases [productName, %]. Shown in the detail card. */
  next: Array<[string, number]>;
}

