"use client";

/**
 * <RelationshipScatter> — Tier-1 signature instrument.
 *
 * "Top-left beats top-right." A two-axis scatter where the vertical (repeat-
 * rate) is the one that matters and the horizontal (volume) is the foil.
 * Bubble size encodes a third weight (LTV). Click-to-select drives a parent
 * detail card via onSelect.
 *
 * Conforms to CHART-STANDARD §2:
 *   - viewBox === real pixel width via useChartSize (rule 2)
 *   - <ChartStates> wraps the SVG (rule 5)
 *   - usePrefersReducedMotion gates the staggered bubble draw + ring beacon
 *   - No `preserveAspectRatio="none"`; no fixed-width viewBox
 *   - Props-driven; sample data exported (rule 4 — §4 data contract)
 *
 * Visual signature: green wash above the catalogue threshold, dashed
 * threshold line, midpoint divider, quadrant labels at the corners, gold
 * corner brackets, hit-targets sized for comfortable click radius, and a
 * radiating ring beacon on the selected bubble.
 */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export type ScatterVerdict = "protect" | "grow" | "watch" | "release";

export const SCATTER_VERDICT_COLOR: Record<ScatterVerdict, string> = {
  protect: "#8b6fc7",
  grow: "#1D9E75",
  watch: "#5B7CB0",
  release: "#d64545",
};

export interface ScatterPoint {
  name: string;
  /** X value (e.g. units sold). */
  vol: number;
  /** Y value as a percentage 0..100 (e.g. repeat-creation rate). */
  rep: number;
  /** Bubble-size weight (e.g. LTV in dollars). */
  ltvN: number;
  verdict: ScatterVerdict;
  /** When true, this point shows its name as a static label even when not selected. */
  emphasize?: boolean;
}

export interface RelationshipScatterProps {
  data: ScatterPoint[];
  /** Index of the currently selected point. */
  selIdx: number;
  onSelect: (i: number) => void;
  /** X-axis upper bound. */
  volMax?: number;
  /** Y-axis upper bound (percent). */
  repMax?: number;
  /** Catalogue threshold drawn as the green-zone divider. */
  repThreshold?: number;
  /** Volume mid-line for the quadrant divider. */
  volMid?: number;
  state?: ChartState;
  height?: number;
  label?: string;
  /** Quadrant labels (in screen reading order: top-left, top-right, bottom-left, bottom-right). */
  quadrants?: [string, string, string, string];
  /** Axis legend labels. */
  axisLabels?: { x: string; y: string };
}

export const sampleScatterData: ScatterPoint[] = [
  { name: "Monthly Subscription", vol: 180, rep: 71, ltvN: 8900, verdict: "protect", emphasize: true },
  { name: "Signature Rose Box", vol: 820, rep: 44, ltvN: 4200, verdict: "grow", emphasize: true },
  { name: "Belgian Chocolate Box", vol: 340, rep: 41, ltvN: 3800, verdict: "grow" },
  { name: "Seasonal Bouquet", vol: 1240, rep: 38, ltvN: 3100, verdict: "grow" },
  { name: "Gift Hamper", vol: 540, rep: 33, ltvN: 3400, verdict: "grow" },
  { name: "Orchid Plant", vol: 420, rep: 27, ltvN: 2600, verdict: "watch" },
  { name: "Single-stem Rose", vol: 360, rep: 14, ltvN: 1100, verdict: "watch" },
  { name: "Graduation Bouquet", vol: 1480, rep: 12, ltvN: 980, verdict: "watch", emphasize: true },
  { name: "Congratulations Stand", vol: 920, rep: 9, ltvN: 760, verdict: "watch" },
  { name: "Funeral Wreath", vol: 410, rep: 4, ltvN: 620, verdict: "watch" },
  { name: "Grand Opening Stand", vol: 280, rep: 6, ltvN: 540, verdict: "release" },
];

export function RelationshipScatter({
  data,
  selIdx,
  onSelect,
  volMax = 1600,
  repMax = 80,
  repThreshold = 25,
  volMid = 620,
  state = "ready",
  height = 480,
  label = "Relationship map",
  quadrants = ["HIDDEN GEMS", "GATEWAYS", "ONE-TIME", "WORKHORSES"],
  axisLabels = { x: "MORE UNITS SOLD →", y: "↑ MORE REPEAT CUSTOMERS" },
}: RelationshipScatterProps) {
  const { ref, width } = useChartSize({ min: 680, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    setDrawn(false);
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  const W = Math.max(680, width);
  const H = height;
  const padL = 14;
  const padR = 20;
  const padT = 34;
  const padB = 54;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;

  const x = (v: number) => padL + (v / volMax) * plotW;
  const y = (r: number) => padT + (1 - r / repMax) * plotH;
  const yThr = y(repThreshold);
  const rad = (v: number) => Math.max(7, Math.sqrt(v) * 0.3);

  return (
    <div ref={ref} className="scatter-wrap" style={{ width: "100%", minHeight: H }}>
      <ChartStates state={state} height={H} label={label}>
        <svg viewBox={`0 0 ${W} ${H}`} width="100%" height={H} style={{ display: "block", overflow: "visible" }}>
          {/* Green zone above threshold */}
          <rect x={padL} y={padT} width={plotW} height={yThr - padT} fill="rgba(29,158,117,0.05)" />

          {/* Horizontal grid */}
          {[0, 20, 40, 60, 80].filter((r) => r <= repMax).map((r) => {
            const yy = y(r);
            return (
              <g key={r}>
                <line x1={padL} y1={yy} x2={W - padR} y2={yy} stroke="rgba(0,0,0,0.05)" strokeWidth={1} />
                <text x={padL + 2} y={yy - 5} fontSize={12} fill="#8a8d94" fontFamily="JetBrains Mono, monospace">
                  {r}%
                </text>
              </g>
            );
          })}

          {/* Threshold + mid-line dividers */}
          <line x1={padL} y1={yThr} x2={W - padR} y2={yThr} stroke="#1D9E75" strokeWidth={1.2} strokeDasharray="5 4" opacity={0.6} />
          <line x1={x(volMid)} y1={padT} x2={x(volMid)} y2={base} stroke="rgba(0,0,0,0.10)" strokeWidth={1} strokeDasharray="3 4" />

          {/* Quadrant labels */}
          <text x={padL + 30} y={padT + 16} fontSize={10} fill="#a7a39a" fontFamily="JetBrains Mono, monospace" letterSpacing="0.14em">
            {quadrants[0]}
          </text>
          <text x={W - padR - 8} y={padT + 16} fontSize={10} fill="#a7a39a" fontFamily="JetBrains Mono, monospace" letterSpacing="0.14em" textAnchor="end">
            {quadrants[1]}
          </text>
          <text x={padL + 30} y={base - 10} fontSize={10} fill="#a7a39a" fontFamily="JetBrains Mono, monospace" letterSpacing="0.14em">
            {quadrants[2]}
          </text>
          <text x={W - padR - 8} y={base - 10} fontSize={10} fill="#a7a39a" fontFamily="JetBrains Mono, monospace" letterSpacing="0.14em" textAnchor="end">
            {quadrants[3]}
          </text>

          {/* Axis legends */}
          <text x={W - padR} y={base + 38} fontSize={10} fill="#8a8d94" fontFamily="JetBrains Mono, monospace" letterSpacing="0.10em" textAnchor="end">
            {axisLabels.x}
          </text>
          <text x={padL} y={base + 38} fontSize={10} fill="#8a8d94" fontFamily="JetBrains Mono, monospace" letterSpacing="0.10em">
            {axisLabels.y}
          </text>

          {/* Gold corner brackets */}
          {[
            [padL, padT + 11, padL, padT, padL + 11, padT],
            [W - padR - 11, padT, W - padR, padT, W - padR, padT + 11],
            [padL, base - 11, padL, base, padL + 11, base],
            [W - padR - 11, base, W - padR, base, W - padR, base - 11],
          ].map((p, i) => (
            <path
              key={i}
              d={`M${p[0]} ${p[1]} L${p[2]} ${p[3]} L${p[4]} ${p[5]}`}
              fill="none"
              stroke="#b88a2a"
              strokeWidth={1}
              opacity={0.5}
            />
          ))}

          {/* Bubbles */}
          {data.map((p, i) => {
            const cx = x(p.vol);
            const cy = y(p.rep);
            const r = rad(p.ltvN);
            const col = SCATTER_VERDICT_COLOR[p.verdict];
            const isSel = i === selIdx;
            const dim = !isSel;
            const delay = 0.2 + i * 0.06;
            return (
              <g key={p.name}>
                <circle
                  cx={cx}
                  cy={cy}
                  r={r}
                  fill={col}
                  fillOpacity={dim ? 0.5 : 0.82}
                  stroke={col}
                  strokeWidth={1}
                  strokeOpacity={dim ? 0.5 : 1}
                  style={{
                    transformBox: "fill-box",
                    transformOrigin: "center",
                    opacity: drawn ? 1 : 0,
                    transition: `opacity 0.5s ${delay}s`,
                  }}
                />
                {p.emphasize && !isSel && (() => {
                  const anchor = p.vol > volMid ? "end" : "start";
                  const lx = p.vol > volMid ? cx - r - 6 : cx + r + 6;
                  return (
                    <text
                      x={lx}
                      y={cy + 4}
                      fontSize={11.5}
                      fill="#3d4047"
                      fontFamily="Inter, sans-serif"
                      fontWeight={500}
                      textAnchor={anchor}
                      style={{
                        opacity: drawn ? 1 : 0,
                        transition: `opacity 0.4s ${delay + 0.3}s`,
                      }}
                    >
                      {p.name}
                    </text>
                  );
                })()}
                {isSel && (() => {
                  const anchor = p.vol > volMid ? "end" : "start";
                  const lx = p.vol > volMid ? cx - r - 9 : cx + r + 9;
                  return (
                    <>
                      <circle cx={cx} cy={cy} r={r + 5} fill="none" stroke="#5B7CB0" strokeWidth={1.5} />
                      {!reduce && (
                        <circle cx={cx} cy={cy} r={r + 5} fill="none" stroke="#5B7CB0" opacity={0.5}>
                          <animate attributeName="r" values={`${r + 5};${r + 22}`} dur="2.2s" repeatCount="indefinite" />
                          <animate attributeName="opacity" values="0.5;0" dur="2.2s" repeatCount="indefinite" />
                        </circle>
                      )}
                      <text x={lx} y={cy - 2} fontSize={11.5} fill="#15171c" fontFamily="Inter, sans-serif" fontWeight={600} textAnchor={anchor}>
                        {p.name}
                      </text>
                      <text x={lx} y={cy + 13} fontSize={10} fill="#3c548a" fontFamily="JetBrains Mono, monospace" fontWeight={600} letterSpacing="0.08em" textAnchor={anchor}>
                        {p.rep}% REPEAT
                      </text>
                    </>
                  );
                })()}
                <circle
                  cx={cx}
                  cy={cy}
                  r={Math.max(r, 13)}
                  fill="transparent"
                  style={{ cursor: "pointer" }}
                  onClick={() => onSelect(i)}
                />
              </g>
            );
          })}
        </svg>
      </ChartStates>
    </div>
  );
}
